import React, {useState, useEffect} from "react";
import "./advicereplyCSS.css";
import Navbaremployee from "./upperlistemployee";
import Cookies from "universal-cookie";

export const AdviceReply = () => {
    const [search, setSearch] = useState('');
    const cookies=new Cookies();
    
    useEffect(() => {
        cookies.set('search',search,{path:'/'});
        console.log(cookies)
    },[search])

    return(
        <>
            <Navbaremployee setSearch={setSearch}/>
            <div className="emailtitle">顧客反映信箱</div>
            <table className="infocolumn">
                <tr>
                    <th className="infocolumn">顧客信箱</th>
                    <th className="infocolumn">顧客信件</th>
                    <th className="infocolumn">回覆</th>
                </tr>
                <tr>
                    <td className="infocolumn"></td>
                </tr>
            </table>
        </>
    );
};
export default AdviceReply;
